@namespace sv_9ae9411b58b54cdb8cd05e19132af5aa.Components.Pages.Settings

<nav class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionSelected.InvokeAsync(section)">
                    <span class="sidebar-icon">@GetIcon(section)</span>
                    @section
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionSelected { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

.settings-sidebar {
    background-color: #f8f9fa;
    border-right: 1px solid #dee2e6;
    min-height: 100%;
    padding: 1rem 0;
    width: 220px;
    flex-shrink: 0;
}

.sidebar-title {
    padding: 0 1rem 0.75rem;
    margin-bottom: 0.5rem;
    border-bottom: 1px solid #dee2e6;
    font-weight: 600;
    color: #495057;
}

.settings-sidebar .nav-link {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.6rem 1rem;
    color: #495057;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    border-left: 3px solid transparent;
    cursor: pointer;
    transition: all 0.15s ease;
}

.settings-sidebar .nav-link:hover {
    background-color: #e9ecef;
    color: #212529;
}

.settings-sidebar .nav-link.active {
    background-color: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

.sidebar-icon {
    font-size: 1.1rem;
}

@namespace sv_9ae9411b58b54cdb8cd05e19132af5aa.Components.Pages.Settings
@using sv_9ae9411b58b54cdb8cd05e19132af5aa.Models

<div class="profile-section">
    <h4>Profile Settings</h4>

    @if (StatusMessage is not null)
    {
        <div class="alert @(IsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
            @StatusMessage
            <button type="button" class="btn-close" @onclick="() => StatusMessage = null"></button>
        </div>
    }

    <div class="avatar-area mb-4">
        <img src="@AvatarUrl" alt="Avatar" class="avatar-preview" />
        <div class="avatar-url-display">
            <label class="form-label">Avatar URL</label>
            <input type="text" class="form-control" value="@AvatarUrl" readonly />
        </div>
    </div>

    <div class="mb-3">
        <label class="form-label">Display Name</label>
        <input type="text" class="form-control" @bind="DisplayName" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <input type="email" class="form-control" @bind="Email" />
    </div>

    <div class="mb-3">
        <label class="form-label">Bio</label>
        <textarea class="form-control" rows="4" @bind="Bio"></textarea>
    </div>

    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
            @if (IsSaving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
    </div>
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string DisplayName { get; set; } = "";
    private string Email { get; set; } = "";
    private string AvatarUrl { get; set; } = "";
    private string Bio { get; set; } = "";
    private string? StatusMessage { get; set; }
    private bool IsError { get; set; }
    private bool IsSaving { get; set; }

    protected override void OnParametersSet()
    {
        if (Profile is not null && !_initialized)
        {
            LoadFromProfile(Profile);
            _initialized = true;
        }
    }

    private bool _initialized;

    private void LoadFromProfile(UserProfile p)
    {
        DisplayName = p.DisplayName;
        Email = p.Email;
        AvatarUrl = p.AvatarUrl;
        Bio = p.Bio;
    }

    private async Task SaveAsync()
    {
        IsSaving = true;
        IsError = false;
        StatusMessage = null;
        try
        {
            var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
            await OnSave.InvokeAsync(updated);
            StatusMessage = "Profile saved successfully!";
        }
        catch
        {
            IsError = true;
            StatusMessage = "Failed to save profile. Please try again.";
        }
        finally
        {
            IsSaving = false;
        }
    }

    private void Discard()
    {
        if (Profile is not null)
        {
            LoadFromProfile(Profile);
        }
        StatusMessage = null;
    }
}

.profile-section {
    max-width: 600px;
}

.avatar-area {
    display: flex;
    align-items: flex-start;
    gap: 1.5rem;
}

.avatar-preview {
    width: 100px;
    height: 100px;
    border-radius: 50%;
    object-fit: cover;
    border: 3px solid #dee2e6;
    flex-shrink: 0;
}

.avatar-url-display {
    flex: 1;
    min-width: 0;
}

@namespace sv_9ae9411b58b54cdb8cd05e19132af5aa.Components.Pages.Settings
@using sv_9ae9411b58b54cdb8cd05e19132af5aa.Models

<div class="notifications-section">
    <h4>Notification Preferences</h4>

    @if (StatusMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @StatusMessage
            <button type="button" class="btn-close" @onclick="() => StatusMessage = null"></button>
        </div>
    }

    <div class="card mb-4">
        <div class="card-body">
            <h6 class="card-title">General</h6>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="EmailNotifications" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="PushNotifications" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>

            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="WeeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h6 class="card-title">Muted Channels</h6>
            <p class="text-muted small">Checked channels are muted.</p>

            @if (AllChannels.Count > 0)
            {
                @foreach (var channel in AllChannels)
                {
                    <div class="form-check mb-2">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                               checked="@MutedSet.Contains(channel)"
                               @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="@($"ch-{channel}")">
                            #@channel
                        </label>
                    </div>
                }
            }
            else
            {
                <p class="text-muted">No channels available.</p>
            }
        </div>
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
        @if (IsSaving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save Preferences
    </button>
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool EmailNotifications { get; set; }
    private bool PushNotifications { get; set; }
    private bool WeeklyDigest { get; set; }
    private HashSet<string> MutedSet { get; set; } = [];
    private List<string> AllChannels { get; set; } = [];
    private string? StatusMessage { get; set; }
    private bool IsSaving { get; set; }
    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !_initialized)
        {
            EmailNotifications = Prefs.EmailNotifications;
            PushNotifications = Prefs.PushNotifications;
            WeeklyDigest = Prefs.WeeklyDigest;
            AllChannels = [.. Prefs.MutedChannels];
            MutedSet = [.. Prefs.MutedChannels];
            _initialized = true;
        }
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            MutedSet.Add(channel);
        else
            MutedSet.Remove(channel);
    }

    private async Task SaveAsync()
    {
        IsSaving = true;
        StatusMessage = null;
        var updated = new NotificationPrefs(
            EmailNotifications, PushNotifications, WeeklyDigest,
            MutedSet.ToList());
        await OnSave.InvokeAsync(updated);
        StatusMessage = "Notification preferences saved!";
        IsSaving = false;
    }
}

.notifications-section {
    max-width: 600px;
}

