@namespace sv_9ae9411b58b54cdb8cd05e19132af5aa.Components.Pages.Settings

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         style="cursor: pointer;" @onclick="Toggle">
        <h6 class="mb-0">🔑 Change Password</h6>
        <span class="expand-icon">@(IsExpanded ? "▲" : "▼")</span>
    </div>
    @if (IsExpanded)
    {
        <div class="card-body">
            @if (StatusMessage is not null)
            {
                <div class="alert @(IsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                    @StatusMessage
                    <button type="button" class="btn-close" @onclick="() => StatusMessage = null"></button>
                </div>
            }

            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="CurrentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="NewPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="ConfirmPassword" />
            </div>
            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@IsUpdating">
                @if (IsUpdating)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool IsExpanded { get; set; }
    private string CurrentPassword { get; set; } = "";
    private string NewPassword { get; set; } = "";
    private string ConfirmPassword { get; set; } = "";
    private string? StatusMessage { get; set; }
    private bool IsError { get; set; }
    private bool IsUpdating { get; set; }

    private void Toggle() => IsExpanded = !IsExpanded;

    private async Task UpdatePasswordAsync()
    {
        StatusMessage = null;
        IsError = false;

        if (string.IsNullOrWhiteSpace(CurrentPassword) ||
            string.IsNullOrWhiteSpace(NewPassword))
        {
            IsError = true;
            StatusMessage = "Please fill in all password fields.";
            return;
        }

        if (NewPassword != ConfirmPassword)
        {
            IsError = true;
            StatusMessage = "New password and confirmation do not match.";
            return;
        }

        IsUpdating = true;
        try
        {
            await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
            StatusMessage = "Password updated successfully!";
            CurrentPassword = "";
            NewPassword = "";
            ConfirmPassword = "";
        }
        catch
        {
            IsError = true;
            StatusMessage = "Failed to change password.";
        }
        finally
        {
            IsUpdating = false;
        }
    }
}

.expand-icon {
    font-size: 0.8rem;
    color: #6c757d;
}

@namespace sv_9ae9411b58b54cdb8cd05e19132af5aa.Components.Pages.Settings

@if (ShowDialog)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal fade show d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke this session?</p>
                    @if (!string.IsNullOrEmpty(DeviceName))
                    {
                        <p class="fw-bold">@DeviceName</p>
                    }
                    <p class="text-muted small">This will sign the session out immediately.</p>
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="Confirm">Revoke</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool ShowDialog { get; set; }
    [Parameter] public string? SessionId { get; set; }
    [Parameter] public string? DeviceName { get; set; }
    [Parameter] public EventCallback<string> OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private async Task Confirm()
    {
        if (SessionId is not null)
            await OnConfirm.InvokeAsync(SessionId);
    }

    private async Task Cancel() => await OnCancel.InvokeAsync();
}

@namespace sv_9ae9411b58b54cdb8cd05e19132af5aa.Components.Pages.Settings
@using sv_9ae9411b58b54cdb8cd05e19132af5aa.Models

<div class="card mb-4">
    <div class="card-body">
        <h6 class="card-title">Active Sessions</h6>
        <div class="table-responsive">
            <table class="table table-hover mb-0">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @if (Sessions is not null)
                    {
                        @foreach (var session in Sessions)
                        {
                            <tr>
                                <td>@session.Device</td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td>
                                    @if (session.Id != CurrentSessionId)
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => RequestRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                    else
                                    {
                                        <span class="badge bg-success">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    }
                </tbody>
            </table>
        </div>
    </div>
</div>

<RevokeSessionDialog ShowDialog="@_showRevokeDialog"
                     SessionId="@_revokeTarget?.Id"
                     DeviceName="@_revokeTarget?.Device"
                     OnConfirm="ConfirmRevoke"
                     OnCancel="CancelRevoke" />

@code {
    [Parameter] public List<ActiveSession>? Sessions { get; set; }
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private bool _showRevokeDialog;
    private ActiveSession? _revokeTarget;

    private void RequestRevoke(ActiveSession session)
    {
        _revokeTarget = session;
        _showRevokeDialog = true;
    }

    private async Task ConfirmRevoke(string sessionId)
    {
        _showRevokeDialog = false;
        _revokeTarget = null;
        await OnRevoke.InvokeAsync(sessionId);
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
        _revokeTarget = null;
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

