@namespace sv_9ae9411b58b54cdb8cd05e19132af5aa.Components.Pages.Settings

@if (ShowDialog)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal fade show d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke this session?</p>
                    @if (!string.IsNullOrEmpty(DeviceName))
                    {
                        <p class="fw-bold">@DeviceName</p>
                    }
                    <p class="text-muted small">This will sign the session out immediately.</p>
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="Confirm">Revoke</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool ShowDialog { get; set; }
    [Parameter] public string? SessionId { get; set; }
    [Parameter] public string? DeviceName { get; set; }
    [Parameter] public EventCallback<string> OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private async Task Confirm()
    {
        if (SessionId is not null)
            await OnConfirm.InvokeAsync(SessionId);
    }

    private async Task Cancel() => await OnCancel.InvokeAsync();
}

@namespace sv_9ae9411b58b54cdb8cd05e19132af5aa.Components.Pages.Settings
