@namespace sv_9ae9411b58b54cdb8cd05e19132af5aa.Components.Pages.Settings
@using sv_9ae9411b58b54cdb8cd05e19132af5aa.Models

<div class="security-section">
    <h4>Security Settings</h4>

    <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

    <div class="card mb-4">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <span class="badge @(TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(TwoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@TwoFactorEnabled"
                           @onchange="e => OnTwoFactorToggle.InvokeAsync((bool)(e.Value ?? false))" />
                </div>
            </div>
            @if (LastPasswordChange.HasValue)
            {
                <p class="text-muted small mt-2 mb-0">
                    Last password change: @LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </p>
            }
        </div>
    </div>

    <ActiveSessionsTable Sessions="@Sessions" OnRevoke="OnRevokeSession" />
</div>

@code {
    [Parameter] public bool TwoFactorEnabled { get; set; }
    [Parameter] public DateTime? LastPasswordChange { get; set; }
    [Parameter] public List<ActiveSession>? Sessions { get; set; }
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<bool> OnTwoFactorToggle { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private async Task HandleChangePassword((string Current, string New) args) =>
        await OnChangePassword.InvokeAsync(args);
}

